import { useState } from 'react';
import { X, Link, Loader2 } from 'lucide-react';
import { api } from '../api/client';

type Props = {
  onClose: () => void;
  onAdded: () => void;
};

type SummarizeResult = {
  title: string;
  summary: string;
  deadline: string | null;
  source_type: 'sns' | 'official' | 'other';
};

export default function AddCampaignModal({ onClose, onAdded }: Props) {
  const [url, setUrl] = useState('');
  const [loading, setLoading] = useState(false);
  const [result, setResult] = useState<SummarizeResult | null>(null);
  const [error, setError] = useState<string | null>(null);

  const handleSummarize = async () => {
    if (!url) return;
    setLoading(true);
    setError(null);
    try {
      const data = await api.summarizeUrl(url);
      setResult(data);
    } catch (e: unknown) {
      setError(e instanceof Error ? e.message : '隕∫ｴ・・ｽ・ｽ螟ｱ謨励＠縺ｾ縺励◆');
    } finally {
      setLoading(false);
    }
  };

  const handleAdd = async () => {
    if (!result) return;
    setLoading(true);
    try {
      await api.addCampaign({
        url,
        title: result.title,
        summary: result.summary,
        deadline: result.deadline,
        source_type: result.source_type,
      });
      onAdded();
    } catch (e: unknown) {
      setError(e instanceof Error ? e.message : '逋ｻ骭ｲ縺ｫ螟ｱ謨励＠縺ｾ縺励◆');
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="fixed inset-0 bg-black/40 flex items-end sm:items-center justify-center z-50">
      <div className="bg-white w-full sm:max-w-lg rounded-t-2xl sm:rounded-2xl p-6">
        <div className="flex items-center justify-between mb-4">
          <h2 className="font-bold text-base">繧ｭ繝｣繝ｳ繝夲ｿｽE繝ｳ繧定ｿｽ蜉</h2>
          <button id="close-modal-btn" onClick={onClose} className="text-gray-400 hover:text-gray-600">
            <X size={20} />
          </button>
        </div>

        {/* URL蜈･蜉・*/}
        <div className="flex gap-2 mb-4">
          <div className="flex-1 flex items-center border rounded-lg px-3 gap-2">
            <Link size={16} className="text-gray-400 shrink-0" />
            <input
              id="url-input"
              type="url"
              placeholder="繧ｭ繝｣繝ｳ繝夲ｿｽE繝ｳ縺ｮURL繧抵ｿｽE蜉・
              value={url}
              onChange={e => setUrl(e.target.value)}
              className="flex-1 text-sm py-2 focus:outline-none"
            />
          </div>
          <button
            id="summarize-btn"
            onClick={handleSummarize}
            disabled={loading || !url}
            className="bg-blue-500 hover:bg-blue-600 text-white rounded-lg px-4 text-sm font-medium disabled:opacity-50 flex items-center gap-1"
          >
            {loading ? <Loader2 size={16} className="animate-spin" /> : '隕∫ｴ・}
          </button>
        </div>

        {error && <p className="text-red-500 text-sm mb-3">{error}</p>}

        {/* LLM隕∫ｴ・・ｽ・ｽ譫懊・繝ｬ繝薙Η繝ｼ */}
        {result && (
          <div className="bg-gray-50 rounded-xl p-4 mb-4 flex flex-col gap-3">
            <div>
              <label className="text-xs text-gray-500 block mb-1">繧ｿ繧､繝医Ν</label>
              <input
                id="title-input"
                type="text"
                value={result.title}
                onChange={e => setResult({ ...result, title: e.target.value })}
                className="w-full text-sm border rounded-lg px-3 py-2 focus:outline-none focus:ring-2 focus:ring-blue-400"
              />
            </div>
            <div>
              <label className="text-xs text-gray-500 block mb-1">隕∫ｴ・/label>
              <textarea
                id="summary-input"
                value={result.summary}
                onChange={e => setResult({ ...result, summary: e.target.value })}
                rows={4}
                className="w-full text-sm border rounded-lg px-3 py-2 focus:outline-none focus:ring-2 focus:ring-blue-400 resize-none"
              />
            </div>
            <div>
              <label className="text-xs text-gray-500 block mb-1">邱繧・ｿｽE繧頑律</label>
              <input
                id="deadline-input"
                type="date"
                value={result.deadline ?? ''}
                onChange={e => setResult({ ...result, deadline: e.target.value || null })}
                className="text-sm border rounded-lg px-3 py-2 focus:outline-none focus:ring-2 focus:ring-blue-400"
              />
            </div>

            <button
              id="add-btn"
              onClick={handleAdd}
              disabled={loading}
              className="bg-blue-500 hover:bg-blue-600 text-white rounded-lg py-2 text-sm font-medium disabled:opacity-50"
            >
              {loading ? '逋ｻ骭ｲ荳ｭ...' : '逋ｻ骭ｲ縺吶ｋ'}
            </button>
          </div>
        )}
      </div>
    </div>
  );
}

import { useState } from 'react';
import { supabase } from '../lib/supabase';

export default function Auth() {
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [isSignUp, setIsSignUp] = useState(false);

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setLoading(true);
    setError(null);

    const { error } = isSignUp
      ? await supabase.auth.signUp({ email, password })
      : await supabase.auth.signInWithPassword({ email, password });

    if (error) setError(error.message);
    setLoading(false);
  };

  return (
    <div className="min-h-screen flex items-center justify-center bg-gray-50">
      <div className="w-full max-w-sm p-8 bg-white rounded-2xl shadow-sm">
        <h1 className="text-2xl font-bold text-center mb-6">繧ｭ繝｣繝ｳ繝夲ｿｽE繝ｳ邂｡逅・/h1>

        <form onSubmit={handleSubmit} className="flex flex-col gap-4">
          <input
            id="email"
            type="email"
            placeholder="繝｡繝ｼ繝ｫ繧｢繝峨Ξ繧ｹ"
            value={email}
            onChange={e => setEmail(e.target.value)}
            required
            className="border rounded-lg px-4 py-2 text-sm focus:outline-none focus:ring-2 focus:ring-blue-400"
          />
          <input
            id="password"
            type="password"
            placeholder="繝代せ繝ｯ繝ｼ繝・
            value={password}
            onChange={e => setPassword(e.target.value)}
            required
            className="border rounded-lg px-4 py-2 text-sm focus:outline-none focus:ring-2 focus:ring-blue-400"
          />

          {error && <p className="text-red-500 text-sm">{error}</p>}

          <button
            id="submit-btn"
            type="submit"
            disabled={loading}
            className="bg-blue-500 hover:bg-blue-600 text-white rounded-lg py-2 text-sm font-medium disabled:opacity-50"
          >
            {loading ? '蜃ｦ逅・・ｽ・ｽ...' : isSignUp ? '譁ｰ隕冗匳骭ｲ' : '繝ｭ繧ｰ繧､繝ｳ'}
          </button>
        </form>

        <button
          id="toggle-mode-btn"
          onClick={() => setIsSignUp(v => !v)}
          className="mt-4 w-full text-center text-sm text-blue-500 hover:underline"
        >
          {isSignUp ? '繝ｭ繧ｰ繧､繝ｳ縺ｯ縺薙■繧・ : '譁ｰ隕冗匳骭ｲ縺ｯ縺薙■繧・}
        </button>
      </div>
    </div>
  );
}

import { ExternalLink, Calendar } from 'lucide-react';
import { api, type Campaign } from '../api/client';

type Props = {
  campaign: Campaign;
  onUpdated: () => void;
};

const STATUS_LABELS: Record<Campaign['status'], string> = {
  active: '蠢懷供荳ｭ',
  applied: '蠢懷供貂医∩',
  closed: '邱繧・ｿｽE繧頑ｸ医∩',
};

export default function CampaignCard({ campaign, onUpdated }: Props) {
  const handleStatusChange = async (status: Campaign['status']) => {
    await api.updateCampaign({ campaign_id: campaign.id, status });
    onUpdated();
  };

  const isExpired = campaign.deadline
    ? new Date(campaign.deadline) < new Date()
    : false;

  return (
    <div className={`bg-white rounded-xl p-4 shadow-sm border ${isExpired ? 'border-red-200' : 'border-gray-100'}`}>
      <div className="flex items-start justify-between gap-2 mb-2">
        <h2 className="font-semibold text-sm leading-snug flex-1">{campaign.title}</h2>
        <a
          href={campaign.url}
          target="_blank"
          rel="noopener noreferrer"
          className="text-gray-400 hover:text-blue-500 shrink-0"
          aria-label="蜈ザRL繧帝幕縺・
        >
          <ExternalLink size={16} />
        </a>
      </div>

      <p className="text-gray-500 text-xs leading-relaxed mb-3 line-clamp-3">
        {campaign.summary}
      </p>

      <div className="flex items-center justify-between gap-2">
        {campaign.deadline ? (
          <span className={`flex items-center gap-1 text-xs ${isExpired ? 'text-red-400' : 'text-gray-400'}`}>
            <Calendar size={12} />
            {campaign.deadline}
          </span>
        ) : (
          <span className="text-xs text-gray-300">邱繧・ｿｽE繧贋ｸ搾ｿｽE</span>
        )}

        <select
          id={`status-select-${campaign.id}`}
          value={campaign.status}
          onChange={e => handleStatusChange(e.target.value as Campaign['status'])}
          className="text-xs border rounded-lg px-2 py-1 bg-gray-50 focus:outline-none"
        >
          {Object.entries(STATUS_LABELS).map(([value, label]) => (
            <option key={value} value={value}>{label}</option>
          ))}
        </select>
      </div>
    </div>
  );
}

import { useState, useEffect, useCallback } from 'react';
import { PlusCircle, LogOut } from 'lucide-react';
import type { Session } from '@supabase/supabase-js';
import { supabase } from '../lib/supabase';
import { api, type Campaign } from '../api/client';
import CampaignCard from './CampaignCard';
import AddCampaignModal from './AddCampaignModal';

type Props = { session: Session };

export default function Home({ session }: Props) {
  const [campaigns, setCampaigns] = useState<Campaign[]>([]);
  const [loading, setLoading] = useState(true);
  const [showAddModal, setShowAddModal] = useState(false);

  const fetchCampaigns = useCallback(async () => {
    try {
      const data = await api.getCampaigns();
      setCampaigns(data);
    } catch (e) {
      console.error(e);
    } finally {
      setLoading(false);
    }
  }, []);

  useEffect(() => {
    fetchCampaigns();
  }, [fetchCampaigns]);

  const handleSignOut = () => supabase.auth.signOut();

  return (
    <div className="min-h-screen bg-gray-50">
      {/* 繝倥ャ繝繝ｼ */}
      <header className="bg-white border-b px-4 py-3 flex items-center justify-between">
        <h1 className="text-lg font-bold">繧ｭ繝｣繝ｳ繝夲ｿｽE繝ｳ邂｡逅・/h1>
        <button
          id="sign-out-btn"
          onClick={handleSignOut}
          className="text-gray-500 hover:text-gray-700"
          aria-label="繝ｭ繧ｰ繧｢繧ｦ繝・
        >
          <LogOut size={20} />
        </button>
      </header>

      {/* 繧ｭ繝｣繝ｳ繝夲ｿｽE繝ｳ荳隕ｧ */}
      <main className="max-w-2xl mx-auto px-4 py-6">
        {loading ? (
          <p className="text-center text-gray-400">隱ｭ縺ｿ霎ｼ縺ｿ荳ｭ...</p>
        ) : campaigns.length === 0 ? (
          <p className="text-center text-gray-400">繧ｭ繝｣繝ｳ繝夲ｿｽE繝ｳ縺後∪縺縺ゅｊ縺ｾ縺帙ｓ</p>
        ) : (
          <div className="flex flex-col gap-3">
            {campaigns.map(c => (
              <CampaignCard
                key={c.id}
                campaign={c}
                onUpdated={fetchCampaigns}
              />
            ))}
          </div>
        )}
      </main>

      {/* 繧ｭ繝｣繝ｳ繝夲ｿｽE繝ｳ霑ｽ蜉繝懊ち繝ｳ */}
      <button
        id="add-campaign-btn"
        onClick={() => setShowAddModal(true)}
        className="fixed bottom-6 right-6 bg-blue-500 hover:bg-blue-600 text-white rounded-full p-4 shadow-lg"
        aria-label="繧ｭ繝｣繝ｳ繝夲ｿｽE繝ｳ繧定ｿｽ蜉"
      >
        <PlusCircle size={24} />
      </button>

      {showAddModal && (
        <AddCampaignModal
          onClose={() => setShowAddModal(false)}
          onAdded={() => { setShowAddModal(false); fetchCampaigns(); }}
        />
      )}
    </div>
  );
}

import { useState } from "react";
import { Plus, Loader2 } from "lucide-react";

interface AddCampaignFormProps {
  onAdd: (url: string) => Promise<void>;
}

export function AddCampaignForm({ onAdd }: AddCampaignFormProps) {
  const [url, setUrl] = useState("");
  const [isLoading, setIsLoading] = useState(false);

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!url.trim()) return;

    setIsLoading(true);
    try {
      await onAdd(url);
      setUrl("");
    } finally {
      setIsLoading(false);
    }
  };

  return (
    <form onSubmit={handleSubmit} className="bg-white rounded-lg border border-gray-200 p-6">
      <div className="flex gap-3">
        <input
          type="url"
          value={url}
          onChange={(e) => setUrl(e.target.value)}
          placeholder="繧ｭ繝｣繝ｳ繝夲ｿｽE繝ｳ縺ｮURL繧抵ｿｽE蜉帙＠縺ｦ縺上□縺輔＞・ｽE・ｽ萓・ https://...・ｽE・ｽE
          className="flex-1 px-4 py-2 border border-gray-300 rounded-lg focus:outline-none focus:ring-2 focus:ring-blue-500 focus:border-transparent"
          disabled={isLoading}
          required
        />
        <button
          type="submit"
          disabled={isLoading || !url.trim()}
          className="px-6 py-2 bg-blue-600 text-white rounded-lg hover:bg-blue-700 disabled:bg-gray-300 disabled:cursor-not-allowed transition-colors flex items-center gap-2 font-medium"
        >
          {isLoading ? (
            <>
              <Loader2 className="w-5 h-5 animate-spin" />
              隗｣譫蝉ｸｭ...
            </>
          ) : (
            <>
              <Plus className="w-5 h-5" />
              霑ｽ蜉
            </>
          )}
        </button>
      </div>
      <p className="text-sm text-gray-500 mt-3">
        SNS繧・・ｽ・ｽ讌ｭ繧ｵ繧､繝茨ｿｽE繧ｭ繝｣繝ｳ繝夲ｿｽE繝ｳURL繧定ｿｽ蜉縺吶ｋ縺ｨ縲、I縺鯉ｿｽE蜍慕噪縺ｫ蜀・・ｽ・ｽ繧定ｦ∫ｴ・・ｽ・ｽ縺ｾ縺・      </p>
    </form>
  );
}

import { useState, useMemo } from "react";
import { Calendar } from "lucide-react";
import type { Campaign } from "../types";
import { CampaignDetailModal } from "./campaign-detail-modal";

interface CalendarViewProps {
  campaigns: Campaign[];
  onDeleteCampaign: (id: string) => void;
  onEditCampaign: (id: string) => void;
}

interface CampaignRow {
  campaign: Campaign;
  row: number;
  startCol: number;
  span: number;
}

export function CalendarView({ campaigns, onDeleteCampaign, onEditCampaign }: CalendarViewProps) {
  const [selectedCampaign, setSelectedCampaign] = useState<Campaign | null>(null);
  
  const today = new Date();
  const currentMonth = today.getMonth();
  const currentYear = today.getFullYear();
  
  const months = useMemo(() => {
    return [
      { month: currentMonth, year: currentYear },
      { month: (currentMonth + 1) % 12, year: currentMonth === 11 ? currentYear + 1 : currentYear },
    ];
  }, [currentMonth, currentYear]);

  const getDaysInMonth = (month: number, year: number) => {
    return new Date(year, month + 1, 0).getDate();
  };

  const getFirstDayOfMonth = (month: number, year: number) => {
    return new Date(year, month, 1).getDay();
  };

  const isToday = (date: Date) => {
    const todayStr = today.toISOString().split("T")[0];
    const dateStr = date.toISOString().split("T")[0];
    return todayStr === dateStr;
  };

  const isPastDate = (date: Date) => {
    const todayStr = today.toISOString().split("T")[0];
    const dateStr = date.toISOString().split("T")[0];
    return dateStr < todayStr;
  };

  // 繧ｭ繝｣繝ｳ繝夲ｿｽE繝ｳ繧定｡後↓驟咲ｽｮ縺吶ｋ繝ｭ繧ｸ繝・・ｽ・ｽ
  const layoutCampaigns = (month: number, year: number) => {
    const firstDay = getFirstDayOfMonth(month, year);
    const daysInMonth = getDaysInMonth(month, year);
    
    // 縺難ｿｽE譛医↓髢｢騾｣縺吶ｋ繧ｭ繝｣繝ｳ繝夲ｿｽE繝ｳ繧貞叙蠕・    const monthStart = new Date(year, month, 1);
    const monthEnd = new Date(year, month, daysInMonth);
    
    const relevantCampaigns = campaigns.filter((campaign) => {
      const campStart = new Date(campaign.startDate);
      const campEnd = new Date(campaign.expiryDate);
      return campStart <= monthEnd && campEnd >= monthStart;
    });

    const campaignRows: CampaignRow[] = [];
    const occupiedCells: boolean[][] = []; // [row][day]

    relevantCampaigns.forEach((campaign) => {
      const campStart = new Date(campaign.startDate);
      const campEnd = new Date(campaign.expiryDate);
      
      // 縺難ｿｽE譛医〒縺ｮ陦ｨ遉ｺ髢句ｧ区律縺ｨ邨ゆｺ・・ｽ・ｽ繧定ｨ育ｮ・      const displayStart = campStart < monthStart ? 1 : campStart.getDate();
      const displayEnd = campEnd > monthEnd ? daysInMonth : campEnd.getDate();
      
      // 繧ｰ繝ｪ繝・・ｽ・ｽ荳奇ｿｽE・ｽE・ｽ・ｽE・ｽ・ｽE・ｽ菴咲ｽｮ繧定ｨ育ｮ暦ｼ磯ｱ縺ｮ髢句ｧ九°繧会ｿｽE繧ｪ繝輔そ繝・・ｽ・ｽ繧貞性繧・ｽE・ｽE      const startCol = firstDay + displayStart - 1;
      const endCol = firstDay + displayEnd - 1;
      const span = endCol - startCol + 1;
      
      // 驟咲ｽｮ蜿ｯ閭ｽ縺ｪ陦後ｒ隕九▽縺代ｋ
      let row = 0;
      while (true) {
        if (!occupiedCells[row]) {
          occupiedCells[row] = [];
        }
        
        // 縺難ｿｽE陦鯉ｿｽEstartCol縺九ｉendCol縺ｾ縺ｧ縺檎ｩｺ縺・・ｽ・ｽ縺・・ｽ・ｽ縺九メ繧ｧ繝・・ｽ・ｽ
        let canPlace = true;
        for (let col = startCol; col <= endCol; col++) {
          if (occupiedCells[row][col]) {
            canPlace = false;
            break;
          }
        }
        
        if (canPlace) {
          // 縺難ｿｽE陦後↓驟咲ｽｮ
          for (let col = startCol; col <= endCol; col++) {
            occupiedCells[row][col] = true;
          }
          campaignRows.push({ campaign, row, startCol, span });
          break;
        }
        
        row++;
      }
    });

    return { campaignRows, maxRow: occupiedCells.length };
  };

  const getCampaignColor = (campaign: Campaign) => {
    // 莨∵･ｭ蜷搾ｿｽE繝上ャ繧ｷ繝･蛟､縺九ｉ濶ｲ繧呈ｱｺ螳・    const hash = campaign.company.split('').reduce((acc, char) => acc + char.charCodeAt(0), 0);
    const colors = [
      'bg-blue-500 hover:bg-blue-600',
      'bg-purple-500 hover:bg-purple-600',
      'bg-green-500 hover:bg-green-600',
      'bg-pink-500 hover:bg-pink-600',
      'bg-indigo-500 hover:bg-indigo-600',
      'bg-orange-500 hover:bg-orange-600',
      'bg-teal-500 hover:bg-teal-600',
    ];
    return colors[hash % colors.length];
  };

  const renderMonth = (month: number, year: number) => {
    const daysInMonth = getDaysInMonth(month, year);
    const firstDay = getFirstDayOfMonth(month, year);
    const { campaignRows, maxRow } = layoutCampaigns(month, year);
    
    const weeks = [];
    let week = [];
    
    // 遨ｺ逋ｽ繧ｻ繝ｫ繧定ｿｽ蜉
    for (let i = 0; i < firstDay; i++) {
      week.push(<div key={`empty-${i}`} className="h-24 border border-gray-200 bg-gray-50" />);
    }
    
    // 譌･莉倥そ繝ｫ繧定ｿｽ蜉
    for (let day = 1; day <= daysInMonth; day++) {
      const date = new Date(year, month, day);
      const isCurrentDay = isToday(date);
      const isPast = isPastDate(date);
      
      week.push(
        <div
          key={day}
          className={`h-24 border border-gray-200 relative ${
            isCurrentDay ? "bg-blue-50" : isPast ? "bg-gray-50" : "bg-white"
          }`}
        >
          <div className={`absolute top-1 right-1 text-sm ${
            isCurrentDay ? "font-bold text-blue-600 bg-blue-600 text-white rounded-full w-6 h-6 flex items-center justify-center" 
            : isPast ? "text-gray-400" : "text-gray-700"
          }`}>
            {day}
          </div>
        </div>
      );
      
      if (week.length === 7) {
        weeks.push(week);
        week = [];
      }
    }
    
    // 譛蠕鯉ｿｽE騾ｱ繧定ｿｽ蜉
    if (week.length > 0) {
      while (week.length < 7) {
        week.push(<div key={`empty-end-${week.length}`} className="h-24 border border-gray-200 bg-gray-50" />);
      }
      weeks.push(week);
    }
    
    return { weeks, campaignRows, maxRow };
  };

  const monthNames = [
    "1譛・, "2譛・, "3譛・, "4譛・, "5譛・, "6譛・,
    "7譛・, "8譛・, "9譛・, "10譛・, "11譛・, "12譛・
  ];
  
  const dayNames = ["譌･", "譛・, "轣ｫ", "豌ｴ", "譛ｨ", "驥・, "蝨・];

  return (
    <>
      <div className="space-y-8">
        {months.map(({ month, year }) => {
          const { weeks, campaignRows } = renderMonth(month, year);
          
          return (
            <div key={`${year}-${month}`} className="bg-white rounded-lg border border-gray-200 p-6">
              <div className="flex items-center gap-2 mb-4">
                <Calendar className="w-5 h-5 text-blue-600" />
                <h2 className="text-xl font-bold text-gray-900">
                  {year}蟷ｴ {monthNames[month]}
                </h2>
              </div>
              
              <div className="relative">
                {/* 譖懈律繝倥ャ繝繝ｼ */}
                <div className="grid grid-cols-7 gap-0 mb-0">
                  {dayNames.map((dayName, index) => (
                    <div
                      key={dayName}
                      className={`text-center font-semibold text-sm py-2 border border-gray-200 ${
                        index === 0 ? "text-red-600 bg-red-50" : index === 6 ? "text-blue-600 bg-blue-50" : "text-gray-700 bg-gray-50"
                      }`}
                    >
                      {dayName}
                    </div>
                  ))}
                </div>
                
                {/* 繧ｫ繝ｬ繝ｳ繝繝ｼ繧ｰ繝ｪ繝・・ｽ・ｽ */}
                <div className="relative">
                  <div className="grid grid-cols-7 gap-0">
                    {weeks.flat()}
                  </div>
                  
                  {/* 繧ｭ繝｣繝ｳ繝夲ｿｽE繝ｳ繝撰ｿｽE・ｽE・ｽ繧ｪ繝ｼ繝撰ｿｽE繝ｬ繧､・ｽE・ｽE*/}
                  <div className="absolute inset-0 pointer-events-none">
                    {campaignRows.map(({ campaign, row, startCol, span }) => {
                      const weekRow = Math.floor(startCol / 7);
                      const colInWeek = startCol % 7;
                      
                      // 騾ｱ繧偵∪縺溘＄蝣ｴ蜷茨ｿｽE蛻・・ｽ・ｽ縺励※陦ｨ遉ｺ
                      const bars = [];
                      let remainingSpan = span;
                      let currentWeekRow = weekRow;
                      let currentCol = colInWeek;
                      
                      while (remainingSpan > 0) {
                        const spaceInWeek = 7 - currentCol;
                        const barSpan = Math.min(remainingSpan, spaceInWeek);
                        
                        bars.push(
                          <div
                            key={`${campaign.id}-${currentWeekRow}-${currentCol}`}
                            className={`absolute pointer-events-auto cursor-pointer ${getCampaignColor(campaign)} text-white px-2 py-1 text-xs font-medium truncate transition-all shadow-sm`}
                            style={{
                              top: `${currentWeekRow * 96 + row * 24 + 28}px`,
                              left: `${(currentCol / 7) * 100}%`,
                              width: `${(barSpan / 7) * 100}%`,
                              height: '20px',
                              borderRadius: currentCol === colInWeek && remainingSpan === span 
                                ? (barSpan === span ? '4px' : '4px 0 0 4px')
                                : (remainingSpan === barSpan ? '0 4px 4px 0' : '0'),
                            }}
                            onClick={() => setSelectedCampaign(campaign)}
                          >
                            {currentCol === colInWeek && (
                              <span>{campaign.company}: {campaign.title}</span>
                            )}
                          </div>
                        );
                        
                        remainingSpan -= barSpan;
                        currentWeekRow++;
                        currentCol = 0;
                      }
                      
                      return bars;
                    })}
                  </div>
                </div>
              </div>
            </div>
          );
        })}
        
        {campaigns.length === 0 && (
          <div className="bg-white rounded-lg border border-gray-200 p-12 text-center">
            <p className="text-gray-500">
              繧ｭ繝｣繝ｳ繝夲ｿｽE繝ｳ縺後∪縺逋ｻ骭ｲ縺輔ｌ縺ｦ縺・・ｽ・ｽ縺帙ｓ縲６RL繧定ｿｽ蜉縺励※縺上□縺輔＞縲・            </p>
          </div>
        )}
      </div>
      
      <CampaignDetailModal
        campaign={selectedCampaign}
        onClose={() => setSelectedCampaign(null)}
        onEdit={onEditCampaign}
      />
    </>
  );
}

